// // This module converts a 24-bit binary input to a 24-bit output, but the output is inverted when the enable signal is high.
module dac_controller (
    input [23:0] data_in,
    input enable,
    output reg [23:0] data_out
);
    always @(*) begin
        if (enable) begin
            data_out = data_in;
        end else begin
            data_out = 24'b0;
        end
    end
endmodule
